// Mautic Config Ensure — additief & non-destructief.
//
// Zet DRY_RUN op false om daadwerkelijk te schrijven. In dry-run (default)
// rapporteert de node alleen wat het ZOU aanmaken; er wordt niets gewijzigd.
//
// De routine maakt ALLEEN aan wat ontbreekt. Bestaande velden, puntgroepen,
// point-acties en segmenten worden nooit overschreven of verwijderd.
//
// Auth loopt via de Mautic OAuth2-credential van n8n (zelfde als de andere
// workflows) met this.helpers.httpRequestWithAuthentication.

const DRY_RUN = true;
const MAUTIC_URL = 'https://connect.devreemakelaardij.nl';
const CRED = 'mauticOAuth2Api';

async function api(method, path, body) {
  return await this.helpers.httpRequestWithAuthentication.call(this, CRED, {
    method,
    url: `${MAUTIC_URL}${path}`,
    body,
    json: true,
  });
}
const call = api.bind(this);

// ─── Gewenste configuratie (declaratief) ──────────────────────────────

// Mautic 7 puntgroepen: gescheiden scores per kans-type.
const pointGroups = [
  { name: 'Koopinteresse', description: 'Signalen die op koopintentie wijzen' },
  { name: 'Verkoopopdracht', description: 'Signalen die op een verkoopopdracht wijzen' },
];

// Contact custom velden (alias = sleutel). Alleen ontbrekende worden aangemaakt.
const contactFields = [
  { alias: 'bezichtiging_interesse', label: 'Bezichtiging interesse', type: 'number' },
  { alias: 'bezichtiging_notities', label: 'Bezichtiging notities', type: 'textarea' },
  { alias: 'kijker_eigen_woning', label: 'Kijker heeft eigen woning', type: 'boolean' },
  { alias: 'kijker_overweegt_verkoop', label: 'Kijker overweegt verkoop', type: 'boolean' },
  { alias: 'kijker_hypotheek_status', label: 'Kijker hypotheek status', type: 'text' },
  { alias: 'verkoopgesprek_status', label: 'Verkoopgesprek status', type: 'text' },
  { alias: 'segment_prioriteit', label: 'Segment prioriteit', type: 'text' },
];

// Point-acties (Mautic-native gedrag). group wordt na aanmaak gekoppeld op naam.
const pointActions = [
  { name: 'E-mail geopend', type: 'email.open', delta: 1, group: 'Koopinteresse' },
  { name: 'E-mail link geklikt', type: 'email.click', delta: 2, group: 'Koopinteresse' },
  { name: 'Woningpagina bezocht', type: 'page.hit', delta: 2, group: 'Koopinteresse' },
  { name: 'Formulier ingevuld', type: 'form.submit', delta: 5, group: 'Koopinteresse' },
];

// Segmenten (publicly: alias + naam). Filters bewust leeg gelaten zodat ze in
// Mautic verfijnd kunnen worden; aanmaken is non-destructief.
const segments = [
  { name: 'Hete kopers', alias: 'hete_kopers', description: 'Hoge koopinteresse / recent warm' },
  { name: 'Verkoop-opdrachtkans', alias: 'verkoop_opdrachtkans', description: 'Eigen woning + overweegt verkoop' },
  { name: 'Herwarmen koud', alias: 'herwarmen_koud', description: 'Opgebouwde punten maar lang stil' },
];

// ─── Ensure-helpers ─────────────────────────────────────────
const report = { dryRun: DRY_RUN, created: [], skipped: [], errors: [] };

async function ensure(label, listPath, listKey, identify, want, createPath, buildBody) {
  let existing = {};
  try {
    const res = await call('GET', `${listPath}?limit=200`);
    existing = res[listKey] || {};
  } catch (e) {
    report.errors.push(`${label}: ophalen mislukt — ${e.message}`);
    return {};
  }
  const existingKeys = new Set(
    Object.values(existing).map((it) => String(identify(it)).toLowerCase())
  );
  const idMap = {};
  for (const it of Object.values(existing)) idMap[String(identify(it)).toLowerCase()] = it.id;

  for (const item of want) {
    const key = String(identify(item)).toLowerCase();
    if (existingKeys.has(key)) {
      report.skipped.push(`${label}: ${key} bestaat al`);
      continue;
    }
    if (DRY_RUN) {
      report.created.push(`${label}: ${key} ZOU worden aangemaakt`);
      continue;
    }
    try {
      const created = await call('POST', createPath, buildBody(item));
      const newId = created[listKey.replace(/s$/, '')]?.id || created?.id;
      if (newId) idMap[key] = newId;
      report.created.push(`${label}: ${key} aangemaakt`);
    } catch (e) {
      report.errors.push(`${label}: ${key} aanmaken mislukt — ${e.message}`);
    }
  }
  return idMap;
}

// 1) Puntgroepen eerst (point-acties verwijzen ernaar).
const groupIds = await ensure(
  'Puntgroep', '/api/points/groups', 'pointGroups',
  (g) => g.name, pointGroups, '/api/points/groups/new',
  (g) => ({ name: g.name, description: g.description })
);

// 2) Contact custom velden.
await ensure(
  'Veld', '/api/fields/contact', 'fields',
  (f) => f.alias, contactFields, '/api/fields/contact/new',
  (f) => ({ label: f.label, alias: f.alias, type: f.type, object: 'lead' })
);

// 3) Point-acties (gekoppeld aan puntgroep waar mogelijk).
await ensure(
  'Point-actie', '/api/points', 'points',
  (p) => p.name, pointActions, '/api/points/new',
  (p) => {
    const body = { name: p.name, type: p.type, delta: p.delta, isPublished: true };
    const gid = groupIds[String(p.group).toLowerCase()];
    if (gid) body.group = gid;
    return body;
  }
);

// 4) Segmenten.
await ensure(
  'Segment', '/api/segments', 'lists',
  (s) => s.alias, segments, '/api/segments/new',
  (s) => ({ name: s.name, alias: s.alias, description: s.description, isPublished: true })
);

return [{ json: report }];
